"use server";

import { serverQuery } from "rwsdk/worker";

export const getRevenue = serverQuery(async () => {
  await new Promise((resolve) => setTimeout(resolve, 1000));
  return "$12,345";
});

export const getUsers = serverQuery(async () => {
  await new Promise((resolve) => setTimeout(resolve, 2000));
  return "1,024 active users";
});

export const getOrders = serverQuery(async () => {
  await new Promise((resolve) => setTimeout(resolve, 3000));
  return "7 orders today";
});

import { getRevenue, getUsers, getOrders } from "./queries";

export async function RevenuePanel() {
  const value = await getRevenue();
  return (
    <div data-panel="revenue" data-state="ready">
      <h2>Revenue</h2>
      <p>{value}</p>
    </div>
  );
}

export async function UsersPanel() {
  const value = await getUsers();
  return (
    <div data-panel="users" data-state="ready">
      <h2>Users</h2>
      <p>{value}</p>
    </div>
  );
}

export async function OrdersPanel() {
  const value = await getOrders();
  return (
    <div data-panel="orders" data-state="ready">
      <h2>Recent Orders</h2>
      <p>{value}</p>
    </div>
  );
}

import { Suspense } from "react";
import { RevenuePanel, UsersPanel, OrdersPanel } from "./panels";

export function DashboardPage() {
  return (
    <main>
      <h1>Dashboard</h1>

      <Suspense
        fallback={
          <div data-panel="revenue" data-state="loading">
            Loading revenue…
          </div>
        }
      >
        <RevenuePanel />
      </Suspense>

      <Suspense
        fallback={
          <div data-panel="users" data-state="loading">
            Loading users…
          </div>
        }
      >
        <UsersPanel />
      </Suspense>

      <Suspense
        fallback={
          <div data-panel="orders" data-state="loading">
            Loading orders…
          </div>
        }
      >
        <OrdersPanel />
      </Suspense>
    </main>
  );
}

